ValidationRule.errorConditionFormula:
AND(
    /* 1. Solo aplica si NO estamos cambiando de etapa */
    NOT(ISCHANGED(StageName)),

    /* 2. Aplica para estas etapas específicas */
    OR(
        TEXT(StageName) = "Approval",
        TEXT(StageName) = "Contract"
    ),

    /* 3. EXCEPCIÓN: Permite el cambio solo si NO se está tocando el campo del contrato */
    NOT(ISCHANGED(Contrato_Cargado__c))
)
